    if characteristic == "Single TCP connection, binary framing, multiplexing":
        return "HTTP/____"
    elif characteristic == "Uses QUIC over UDP for faster handshakes and no HOL blocking":
        return "HTTP/____"
    elif characteristic == "Text-based, one request per connection (unless Keep-Alive)":
        return "HTTP/____"
